// === 短信后端配置 ===
// 短信服务已集成到后端代理服务
const SMS_API=''; // 不再需要单独地址，统一使用 BACKEND_URL
const SMS_ENABLED=true;                        // 后端代理已集成短信服务

// === 后端代理 API 辅助函数 ===
async function aiProxy(endpoint, body) {
  const token = localStorage.getItem('lsjy_backend_token');
  if (!token) return { error: '未登录，请先登录后使用 AI 功能' };
  try {
    const r = await fetch(BACKEND_URL + endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
      body: JSON.stringify(body),
    });
    const data = await r.json();
    if (!r.ok) return { error: data.error || 'AI 服务异常' };
    return data;
  } catch (e) {
    return { error: '网络连接失败，请检查网络后重试' };
  }
}

// 短信发送（后端代理）
async function sendSmsCode(phone) {
  try {
    const r = await fetch(BACKEND_URL + '/api/sms/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ phone }),
    });
    return await r.json();
  } catch (e) {
    return { error: '短信发送失败' };
  }
}

// 短信验证（后端代理）
async function verifySmsCode(phone, code) {
  try {
    const r = await fetch(BACKEND_URL + '/api/sms/verify', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ phone, code }),
    });
    return await r.json();
  } catch (e) {
    return { error: '验证失败' };
  }
}

